/* =========================================================
   JALOLIDDIN PORTFOLIO — script.js
   Vanilla JS: loader, cursor, particles, nav, typing,
   reveal, portfolio cards, project filters, contact, ripple
   ========================================================= */

(function () {
  'use strict';

  /* ---------- Loader ---------- */
  window.addEventListener('load', () => {
    const loader = document.getElementById('loader');
    if (loader) setTimeout(() => loader.classList.add('hidden'), 1400);
  });

  /* ---------- Custom Cursor + Glow ---------- */
  const cursor = document.getElementById('cursor');
  const dot = document.getElementById('cursorDot');
  const glow = document.getElementById('mouseGlow');
  let mx = window.innerWidth / 2, my = window.innerHeight / 2;
  let gx = mx, gy = my;

  if (cursor && dot && glow && window.matchMedia('(min-width: 901px)').matches) {
    window.addEventListener('mousemove', (e) => {
      mx = e.clientX; my = e.clientY;
      cursor.style.left = mx + 'px'; cursor.style.top = my + 'px';
      dot.style.left = mx + 'px'; dot.style.top = my + 'px';
    });
    const tickGlow = () => {
      gx += (mx - gx) * 0.08; gy += (my - gy) * 0.08;
      glow.style.left = gx + 'px'; glow.style.top = gy + 'px';
      requestAnimationFrame(tickGlow);
    };
    tickGlow();

    document.addEventListener('mouseover', (e) => {
      const t = e.target;
      if (t.closest('a, button, .pcard, .proj, .service, .chip, .social, input, textarea')) {
        cursor.classList.add('hover');
      }
    });
    document.addEventListener('mouseout', () => cursor.classList.remove('hover'));
  }

  /* ---------- Particle Background ---------- */
  const canvas = document.getElementById('particles');
  if (canvas) {
    const ctx = canvas.getContext('2d');
    let w, h, particles;
    const COUNT = 60;

    function resize() {
      w = canvas.width = window.innerWidth;
      h = canvas.height = window.innerHeight;
    }
    function makeParticles() {
      particles = Array.from({ length: COUNT }, () => ({
        x: Math.random() * w, y: Math.random() * h,
        r: Math.random() * 2 + 0.6,
        vx: (Math.random() - 0.5) * 0.4,
        vy: (Math.random() - 0.5) * 0.4,
        a: Math.random() * 0.5 + 0.2,
      }));
    }
    function draw() {
      ctx.clearRect(0, 0, w, h);
      for (const p of particles) {
        p.x += p.vx; p.y += p.vy;
        if (p.x < 0 || p.x > w) p.vx *= -1;
        if (p.y < 0 || p.y > h) p.vy *= -1;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255, 107, 0, ' + p.a + ')';
        ctx.shadowColor = 'rgba(255, 107, 0, 0.8)';
        ctx.shadowBlur = 8;
        ctx.fill();
      }
      requestAnimationFrame(draw);
    }
    resize(); makeParticles(); draw();
    window.addEventListener('resize', () => { resize(); makeParticles(); });
  }

  /* ---------- Navigation: scroll state, mobile toggle, active link ---------- */
  const nav = document.getElementById('nav');
  const navMenu = document.getElementById('navMenu');
  const navToggle = document.getElementById('navToggle');
  const links = Array.from(document.querySelectorAll('.nav__link[href^="#"]'));

  if (navToggle && navMenu) {
    navToggle.addEventListener('click', () => {
      navMenu.classList.toggle('open');
      navToggle.classList.toggle('open');
    });
    navMenu.addEventListener('click', (e) => {
      if (e.target.tagName === 'A') {
        navMenu.classList.remove('open');
        navToggle.classList.remove('open');
      }
    });
  }

  const sections = links
    .map(l => document.querySelector(l.getAttribute('href')))
    .filter(Boolean);

  function onScroll() {
    const y = window.scrollY;
    if (nav) nav.classList.toggle('scrolled', y > 30);

    // progress bar
    const sp = document.getElementById('scrollProgress');
    const docH = document.documentElement.scrollHeight - window.innerHeight;
    if (sp) sp.style.width = (docH > 0 ? (y / docH) * 100 : 0) + '%';

    // to-top
    const tt = document.getElementById('toTop');
    if (tt) tt.classList.toggle('show', y > 600);

    // active link
    let current = sections[0]?.id || '';
    for (const s of sections) {
      if (s.offsetTop - 140 <= y) current = s.id;
    }
    links.forEach(l => l.classList.toggle('active', l.getAttribute('href') === '#' + current));
  }
  window.addEventListener('scroll', onScroll, { passive: true });
  onScroll();

  /* ---------- Scroll-to-top ---------- */
  const toTop = document.getElementById('toTop');
  if (toTop) toTop.addEventListener('click', () => window.scrollTo({ top: 0, behavior: 'smooth' }));

  /* ---------- Typing Animation ---------- */
  const typed = document.getElementById('typed');
  if (typed) {
    const phrases = ['Creative Developer', 'Frontend Developer', 'UI/UX Designer'];
    let pi = 0, ci = 0, deleting = false;
    function type() {
      const cur = phrases[pi];
      if (!deleting) {
        typed.textContent = cur.slice(0, ++ci);
        if (ci === cur.length) { deleting = true; setTimeout(type, 1400); return; }
      } else {
        typed.textContent = cur.slice(0, --ci);
        if (ci === 0) { deleting = false; pi = (pi + 1) % phrases.length; }
      }
      setTimeout(type, deleting ? 45 : 90);
    }
    type();
  }

  /* ---------- Reveal on Scroll ---------- */
  const reveals = document.querySelectorAll('.reveal');
  const io = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        e.target.classList.add('in');
        // Animate skill bars when their column reveals
        e.target.querySelectorAll?.('.skill__bar span[data-w]').forEach(s => {
          s.style.width = s.dataset.w + '%';
        });
        io.unobserve(e.target);
      }
    });
  }, { threshold: 0.12 });
  reveals.forEach(r => io.observe(r));

  // Also catch skill bars inside already-revealed columns
  document.querySelectorAll('.skills__col').forEach(col => {
    const barIO = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          col.querySelectorAll('.skill__bar span[data-w]').forEach(s => s.style.width = s.dataset.w + '%');
          barIO.unobserve(col);
        }
      });
    }, { threshold: 0.3 });
    barIO.observe(col);
  });

  /* ---------- Portfolio Cards ---------- */
  // Easy to replace: edit the array below with your own images, titles, etc.
  const portfolioItems = [
    { title: 'Pulse Music', desc: 'Immersive music player UI with waveform visualizations.', tech: ['React', 'Web Audio', 'Framer'], img: 'https://images.pexels.com/photos/1763075/pexels-photo-1763075.jpeg?auto=compress&cs=tinysrgb&w=800', demo: '#', code: '#' },
    { title: 'Prime Travel', desc: 'Travel booking platform with elegant search and maps.', tech: ['Tilda', 'HTML', 'CSS'], img: 'photo_2026-06-19_18-47-38.jpg', demo: '#', code: '#' },
    { title: 'Vertex CRM', desc: 'Customer relationship dashboard with kanban and insights.', tech: ['React', 'Supabase', 'Tailwind'], img: 'https://images.pexels.com/photos/3184465/pexels-photo-3184465.jpeg?auto=compress&cs=tinysrgb&w=800', demo: '#', code: '#' },
    { title: 'Prime Translation', desc: 'Experienced translation platform with real-time collaboration.', tech: ['React', 'PWA', 'Charts'], img: 'data:image/jpeg;base64,', demo: '#', code: '#' },
  ];

  const pGrid = document.getElementById('portfolioGrid');
  if (pGrid) {
    portfolioItems.forEach((p, i) => {
      const card = document.createElement('article');
      card.className = 'pcard reveal';
      card.style.transitionDelay = (i % 4) * 0.08 + 's';
      card.innerHTML = `
        <div class="pcard__media">
          <img src="${p.img}" alt="${p.title} preview" loading="lazy" />
        </div>
        <div class="pcard__body">
          <h3 class="pcard__title">${p.title}</h3>
          <p class="pcard__desc">${p.desc}</p>
          <div class="pcard__tech">${p.tech.map(t => `<span>${t}</span>`).join('')}</div>
          <div class="pcard__actions">
            <a href="${p.demo}" class="btn btn--primary ripple" target="_blank" rel="noopener">Live Demo</a>
            <a href="${p.code}" class="btn btn--ghost ripple" target="_blank" rel="noopener">Source</a>
          </div>
        </div>
      `;
      pGrid.appendChild(card);
      io.observe(card);
    });
  }

  /* ---------- Projects (filterable) ---------- */
  const projects = [
    { cat: 'web', title: 'Stellar Web', desc: 'A high-performance marketing site with motion design.' },
    { cat: 'mobile', title: 'Flow Mobile', desc: 'Cross-platform mobile app with offline-first sync.' },
    { cat: 'design', title: 'Halo Design System', desc: 'A scalable design system with tokens and components.' },
    { cat: 'branding', title: 'Ember Brand', desc: 'Identity and brand guidelines for a tech startup.' },
    { cat: 'web', title: 'Quartz Admin', desc: 'Admin panel with role-based access and rich tables.' },
    { cat: 'design', title: 'Lumen UI Kit', desc: 'A premium UI kit of 120+ components in Figma.' },
    { cat: 'mobile', title: 'Drift Wallet', desc: 'Mobile crypto wallet with biometric security.' },
    { cat: 'branding', title: 'Nova Studio', desc: 'Brand identity for a creative studio.' },
    { cat: 'web', title: 'Cobalt SaaS', desc: 'Multi-tenant SaaS landing and dashboard suite.' },
  ];

  const projGrid = document.getElementById('projectsGrid');
  if (projGrid) {
    projects.forEach((p, i) => {
      const card = document.createElement('article');
      card.className = 'proj reveal';
      card.dataset.cat = p.cat;
      card.style.transitionDelay = (i % 3) * 0.08 + 's';
      card.innerHTML = `
        <span class="proj__cat">${p.cat}</span>
        <h3 class="proj__title">${p.title}</h3>
        <p class="proj__desc">${p.desc}</p>
        <a href="#" class="proj__link">View case study →</a>
      `;
      projGrid.appendChild(card);
      io.observe(card);
    });
  }

  const filters = document.getElementById('projectFilters');
  if (filters) {
    filters.addEventListener('click', (e) => {
      const btn = e.target.closest('.chip');
      if (!btn) return;
      filters.querySelectorAll('.chip').forEach(c => c.classList.remove('active'));
      btn.classList.add('active');
      const f = btn.dataset.filter;
      document.querySelectorAll('.proj').forEach(p => {
        const show = f === 'all' || p.dataset.cat === f;
        p.classList.toggle('hide', !show);
      });
    });
  }

  /* ---------- Contact Form ---------- */
  const contactForm = document.getElementById('contactForm');
  const contactStatus = document.getElementById('contactStatus');
  if (contactForm) {
    contactForm.addEventListener('submit', (e) => {
      e.preventDefault();
      contactStatus.style.color = 'var(--orange)';
      contactStatus.textContent = 'Sending your message...';
      setTimeout(() => {
        contactStatus.style.color = '#0a8a4a';
        contactStatus.textContent = 'Thank you! Your message has been sent.';
        contactForm.reset();
      }, 1200);
    });
  }

  /* ---------- Ripple Effect ---------- */
  document.addEventListener('click', (e) => {
    const btn = e.target.closest('.ripple');
    if (!btn) return;
    const rect = btn.getBoundingClientRect();
    const r = document.createElement('span');
    r.className = 'rip';
    r.style.left = (e.clientX - rect.left) + 'px';
    r.style.top = (e.clientY - rect.top) + 'px';
    r.style.width = r.style.height = Math.max(rect.width, rect.height) / 2 + 'px';
    btn.appendChild(r);
    setTimeout(() => r.remove(), 700);
  });

  /* ---------- Footer Year ---------- */
  const yearEl = document.getElementById('year');
  if (yearEl) yearEl.textContent = new Date().getFullYear();

  /* ---------- Hero parallax shapes ---------- */
  const shapes = document.querySelectorAll('.shape');
  if (shapes.length && window.matchMedia('(min-width: 901px)').matches) {
    window.addEventListener('mousemove', (e) => {
      const x = (e.clientX / window.innerWidth - 0.5);
      const y = (e.clientY / window.innerHeight - 0.5);
      shapes.forEach((s, i) => {
        const depth = (i + 1) * 8;
        s.style.transform = `translate(${x * depth}px, ${y * depth}px)`;
      });
    });
  }
})();
